 56ÔåÆ### 1. Datenpersistenz ÔÇö Remote Functions
 57ÔåÆ
 58ÔåÆAlle Daten werden serverseitig in Turso gespeichert. Zugriff ausschlie├ƒlich ├╝ber SvelteKit Remote Functions. **KEIN localStorage.**
 59ÔåÆ
 60ÔåÆ```typescript
 61ÔåÆ// src/lib/rpc/auditoren.remote.ts
 62ÔåÆimport { query, mutation } from '$app/server';
 63ÔåÆimport { db } from '$lib/server/db';
 64ÔåÆimport { auditors } from '$db/schema';
 65ÔåÆimport { eq } from 'drizzle-orm';
 66ÔåÆ
 67ÔåÆ// Leseoperationen: query()
 68ÔåÆexport const getAuditors = query(async () => {
 69ÔåÆ	return db.select().from(auditors);
 70ÔåÆ});
 71ÔåÆ
 72ÔåÆexport const getAuditorById = query(async (id: string) => {
 73ÔåÆ	return db.select().from(auditors).where(eq(auditors.id, id));
 74ÔåÆ});
 75ÔåÆ
 76ÔåÆ// Schreiboperationen: mutation()
 77ÔåÆexport const deleteAuditor = mutation(async (id: string) => {
 78ÔåÆ	await db.delete(auditors).where(eq(auditors.id, id));
 79ÔåÆ});
 80ÔåÆ```
