101ÔåÆAlle Formulare verwenden SvelteKit Form Actions mit SuperForms + Zod:
102ÔåÆ
103ÔåÆ```typescript
104ÔåÆ// src/routes/(app)/auditor-neu/+page.server.ts
105ÔåÆimport { fail, message, superValidate } from 'sveltekit-superforms';
106ÔåÆimport { zod4 } from 'sveltekit-superforms/adapters';
107ÔåÆimport { z } from 'zod';
108ÔåÆ
109ÔåÆconst auditorSchema = z.object({
110ÔåÆ	name: z.string().min(1, 'Name ist erforderlich'),
111ÔåÆ	email: z.email('Ung├╝ltige E-Mail-Adresse'),
112ÔåÆ	company: z.string().optional()
113ÔåÆ});
114ÔåÆ
115ÔåÆexport const load = async () => {
116ÔåÆ	const form = await superValidate(zod4(auditorSchema));
117ÔåÆ	return { form };
118ÔåÆ};
119ÔåÆ
120ÔåÆexport const actions = {
121ÔåÆ	default: async (event) => {
122ÔåÆ		const form = await superValidate(event, zod4(auditorSchema));
123ÔåÆ		if (!form.valid) return fail(400, { form });
124ÔåÆ		// DB-Operation...
125ÔåÆ		return message(form, 'Auditor gespeichert!');
